"use client";
import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useEffect } from "react";
import { FaFacebook, FaInstagram, FaYoutube } from "react-icons/fa";

export default function ProfilePage() {
  const { data: session, status } = useSession();
  const router = useRouter();

  useEffect(() => {
    if (status === "unauthenticated") {
      router.push("/login");
    }
  }, [status, router]);

  if (status === "loading") return <p className="text-center mt-10">Loading...</p>;

  const user = session?.user;

  return (
    <div className="max-w-3xl mx-auto mt-10 p-6 border border-gray-300 rounded-lg shadow-md bg-white">
      <h1 className="text-3xl font-bold mb-6 text-center">My Profile</h1>

      <div className="space-y-4 text-lg">
        <p><strong>Username:</strong> {user?.username}</p>
        <p><strong>Email:</strong> {user?.email}</p>
        <p><strong>Phone:</strong> {user?.phone}</p>
        <p><strong>Role:</strong> {user?.role}</p>
        <p><strong>Created At:</strong> {new Date(user?.createdAt).toLocaleString()}</p>
        <p><strong>Updated At:</strong> {new Date(user?.updatedAt).toLocaleString()}</p>
      </div>

      {/* Social Links */}
      <div className="mt-6">
        <h2 className="text-xl font-semibold mb-2">Social Links</h2>
        <div className="flex gap-4 text-2xl">
          {user?.youtube && (
            <a href={user.youtube} target="_blank" rel="noopener noreferrer" className="text-red-600 hover:scale-110 transition">
              <FaYoutube />
            </a>
          )}
          {user?.facebook && (
            <a href={user.facebook} target="_blank" rel="noopener noreferrer" className="text-blue-700 hover:scale-110 transition">
              <FaFacebook />
            </a>
          )}
          {user?.instagram && (
            <a href={user.instagram} target="_blank" rel="noopener noreferrer" className="text-pink-500 hover:scale-110 transition">
              <FaInstagram />
            </a>
          )}
          {!user?.youtube && !user?.facebook && !user?.instagram && (
            <p className="text-gray-500">No social links available</p>
          )}
        </div>
      </div>

      <div className="mt-8 flex justify-center">
        <button
          onClick={() => router.push(`/profile/${user.id}/edit`)}
          className="px-6 py-2 bg-black text-white rounded shadow-md hover:bg-gray-800 transition"
        >
          Update Profile
        </button>
      </div>
    </div>
  );
}
